var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"윽! 모래 폭풍이 다시 거세지고 있어요!","JPN":"うっ！　砂嵐がまた強くなってます！","ENG":"Ngh! The sandstorm is getting stronger again!","TWN":"唔！沙塵暴又變得更猛烈了！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아닐라. 저 안에 있는 동안 훈련을 게을리하지는 않았나?","JPN":"アニラ。あの中にいる間に、訓練を怠っていたわけではないだろうな。","ENG":"Anila. Have you neglected your training inside that thing?","TWN":"雅妮拉，你在這裡的時候沒有偷懶忘記訓練吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그럴리가요. 누가 가르쳤는데.","JPN":"そんな。誰に教わったと思っているんですか？","ENG":"Of course, not. Did you forget who trained me?","TWN":"怎麼可能，也不看看是誰教我的。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"확인해보시겠어요?","JPN":"確かめてみます？","ENG":"Or do you want to see for yourself?","TWN":"要來確認一下嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"폭풍이…… 사라졌어?","JPN":"嵐が……消えた？","ENG":"The storm... disappeared?","TWN":"沙塵暴……消失了？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"이번에야말로 반드시 마무리 짓겠습니다.","JPN":"今度こそ必ず終わらせます。","ENG":"I will make sure to end it this time.","TWN":"這次一定能結束這一切的。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"하지만 놈을 붙잡기 위해선 차원 닻이 필요해요. 차원 닻을 시동할 시간을 벌어야 합니다.","JPN":"ですが、やつを捕まえるためには次元錨が必要です。次元錨を始動する時間を稼がなければいけません。","ENG":"But in order to catch it, we need the Dimension Anchor and enough time to get it started.","TWN":"但是要抓住它，必須使用次元錨。現在要爭取啟動次元錨的時間。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"시간을 끌 녀석들은 충분하지.","JPN":"時間を稼いでくれるやつらなら十分だ。","ENG":"We have enough people who will buy us some time.","TWN":"有人可以幫我們爭取足夠的時間。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"반드시 날 도와주기로 약속했거든.","JPN":"必ず私に協力すると約束したからな。","ENG":"They promised to come help.","TWN":"他們答應過一定會幫我的。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"바루나스트라를 향해 포격이?","JPN":"ヴァルナストラに向かって砲撃が？","ENG":"A bombardment toward Varunastra?","TWN":"是誰在向那個鯨魚開炮？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"설마……?","JPN":"まさか……？","ENG":"Could it be...?","TWN":"難道說……？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"모래 폭풍이 걷힌 걸 확인하고 곧장 달려왔다. 늦지 않았군.","JPN":"砂嵐が治まったところを確認してすぐに駆けつけてきた。間に合ったな。","ENG":"We came as soon as we saw that the sandstorm had cleared. I'm glad we made it in time.","TWN":"沙塵暴結束後，我們就立刻趕過來，幸好還不晚。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"저 침식체 새끼를 갉아 먹으러 돌아왔다고! 그렇지, 마리?","JPN":"あの侵食体の野郎を倒すために戻ってきたんだ！　そうだろう？　マリー！","ENG":"We're back to rip that C.O. a new one! Isn't that right, Marie?","TWN":"我們是回來啃食那個侵蝕體的！對吧，瑪麗？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"적 개체 포착했습니다. 침식파 측정 결과…… 오류?","JPN":"敵個体を捕らえました。侵食波測定の結果……エラー？","ENG":"Enemy entity detected. The Corruption ray measurement results are– An error?","TWN":"發現敵人，侵蝕波測量結果……出錯？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"게다가 차원 계면이 융해되기 시작했어요. 이대로라면 침식체가 도주합니다.","JPN":"さらに次元界面が融解し始めました。このままだと侵食体が逃走します。","ENG":"What's worse is that the dimension surface has started to melt. The C.O. will escape at this rate.","TWN":"次元邊界已經開始瓦解，再這樣下去，侵蝕體會逃走的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OPR_VARUNA_NPC_ADMIN","text":{"KOREA":"역시 파티마씨를 불러오는 게…….","JPN":"やはりファティマさんをお呼びした方が……","ENG":"I knew we should've called Fatima for help...","TWN":"果然還是要找法蒂瑪來……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"OPR_VARUNA_NPC_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_A","text":{"KOREA":"그럴 필요 없어 아가씨. 저 여자의 실력은 내가 장담하지.","JPN":"その必要はない、お嬢さん。あの女の実力は俺が保証する。","ENG":"No need for that. I can vouch for what that woman can do.","TWN":"不需要，那個女人的實力我可以作證。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"우리는 그냥 멀리서 엄호만 해주면 된 단 말씀!","JPN":"俺たちはただ遠くから援護するだけでいいってこった！","ENG":"All we need to do is provide cover from afar!","TWN":"我們只需要在遠處掩護她就好！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DESERT_VARUNA_NPC_B","text":{"KOREA":"마리도 몸이 근질근질해서 포신 움직이는 것 좀 봐~","JPN":"マリもムズムズして砲身が動いてるぜ～","ENG":"Look at how restless Marie is with her gun barrel twitching!","TWN":"瑪麗等不及要大展身手囉，看看她舞動炮管的樣子～"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"DESERT_VARUNA_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DESERT_VARUNA_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아샤! 저와 함께 차원 닻을 시동해야 해요.","JPN":"アーシャ！　私と一緒に次元錨に始動をかけるのです。","ENG":"Asha! You need to start the Dimension Anchor with me!","TWN":"阿莎！你來和我一起啟動次元錨。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"네? 하, 하지만 저희 둘 다 무슨 코드가 맞지 않는다고…….","JPN":"えっ？　で、でも、私たち二人ともコードが合わないって……","ENG":"What? B-but isn't it said that our code doesn't match...?","TWN":"可是？等一下，不是說需要啟動代碼……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"분명 부전대장님은 방법을 마련했을 겁니다.","JPN":"副戦隊長ならきっと、何かしらの方法を考えておいたはずです。","ENG":"I'm sure Deputy Commander left us with a way to start it.","TWN":"副戰隊長一定有先想好辦法。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그리고 그건 아마 당신과 함께하지 않으면 해낼 수 없을 거예요.","JPN":"そしてそれはおそらくあなたと一緒でないとできないでしょう。","ENG":"And I probably can't do it without you.","TWN":"而且那可能只有和你一起才能完成。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};